class Solution {
public:
    int countLargestGroup(int n) {
        unordered_map<int, int> mp;
        for (int i = 1; i <= n; i++) {
            int sum = 0;
            for (int j = i; j; j /= 10) {
                sum += j % 10;
            }
            mp[sum]++;
        }
        int maxCount = 0;
        int res = 0;
        for (auto p : mp) {
            if (p.second > maxCount) {
                maxCount = p.second;
                res = 1;
            } else if (p.second == maxCount) {
                res++;
            }
        }
        return res;
    }
};
```
